// Generated by forge proof from mcp-structured-watch.md
import { describe, test, expect, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import type { SessionEvent, SessionStartEvent, SessionEndEvent } from './types.js';

// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-mcp-watch-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
});

function makeSessionStart(overrides: Partial<SessionStartEvent> = {}): SessionStartEvent {
  return {
    type: 'session_start',
    timestamp: new Date().toISOString(),
    sessionId: 'test-session',
    model: 'sonnet',
    prompt: 'test',
    ...overrides,
  };
}

function makeSessionEnd(overrides: Partial<SessionEndEvent> = {}): SessionEndEvent {
  return {
    type: 'session_end',
    timestamp: new Date().toISOString(),
    durationSeconds: 60,
    status: 'success',
    ...overrides,
  };
}

/** Set up a session directory with latest-session.json, stream.log, and optionally events.jsonl */
async function setupSession(
  baseDir: string,
  sessionId: string,
  opts: { events?: SessionEvent[]; streamLog?: string },
): Promise<{ logPath: string; eventsPath: string }> {
  const sessionDir = path.join(baseDir, '.forge', 'sessions', sessionId);
  await fs.mkdir(sessionDir, { recursive: true });

  const logPath = path.join(sessionDir, 'stream.log');
  const eventsPath = path.join(sessionDir, 'events.jsonl');

  // Always write stream.log
  await fs.writeFile(logPath, opts.streamLog ?? '[2026-01-01T00:00:00Z] Session started\n');

  // Write events.jsonl only if events provided
  if (opts.events) {
    await fs.writeFile(eventsPath, opts.events.map(e => JSON.stringify(e)).join('\n'));
  }

  // Write latest-session.json
  const latestPath = path.join(baseDir, '.forge', 'latest-session.json');
  await fs.writeFile(latestPath, JSON.stringify({ sessionId, logPath }));

  return { logPath, eventsPath };
}

/**
 * Simulate the forge_watch handler's format detection logic.
 * This mirrors what src/mcp.ts forge_watch does internally.
 */
async function simulateWatchHandler(
  cwd: string,
  maxLines: number = 40,
): Promise<{ format: 'structured' | 'legacy'; events?: Record<string, unknown>[]; activity?: string[]; session: string | null }> {
  const latestPath = path.join(cwd, '.forge', 'latest-session.json');
  let sessionId: string | undefined;
  let logPath: string | undefined;

  try {
    const data = JSON.parse(await fs.readFile(latestPath, 'utf-8'));
    sessionId = data.sessionId;
    logPath = data.logPath;
  } catch {
    return { format: 'legacy', session: null };
  }

  if (!logPath) {
    return { format: 'legacy', session: sessionId ?? null };
  }

  // Check for events.jsonl alongside stream.log
  const eventsPath = logPath.replace(/stream\.log$/, 'events.jsonl');
  let hasEvents = false;
  if (eventsPath !== logPath) {
    try {
      await fs.access(eventsPath);
      hasEvents = true;
    } catch { /* not found */ }
  }

  if (hasEvents) {
    // Structured mode: read events.jsonl
    const content = await fs.readFile(eventsPath, 'utf-8');
    const allLines = content.split('\n').filter(l => l.trim());
    const recentLines = allLines.slice(-maxLines);

    const events: Record<string, unknown>[] = [];
    for (const line of recentLines) {
      try { events.push(JSON.parse(line)); } catch { /* skip */ }
    }

    return { format: 'structured', events, session: sessionId ?? null };
  }

  // Legacy mode: read stream.log
  const content = await fs.readFile(logPath, 'utf-8');
  const allLines = content.split('\n').filter(l => l.trim());
  const recentLines = allLines.slice(-maxLines);
  const cleanLines = recentLines.map(l => l.replace(/\x1b\[[0-9;]*m/g, ''));

  return { format: 'legacy', activity: cleanLines, session: sessionId ?? null };
}

// ── Format detection ─────────────────────────────────────────

describe('forge_watch format detection', () => {
  test('returns "structured" format when events.jsonl exists', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'struct-1' }),
      { type: 'text_delta', timestamp: new Date().toISOString(), content: 'hello' },
      makeSessionEnd(),
    ];
    await setupSession(dir, 'struct-1', { events });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('structured');
    expect(result.events).toBeDefined();
    expect(result.events!.length).toBe(3);
    expect(result.session).toBe('struct-1');
  });

  test('returns "legacy" format when only stream.log exists', async () => {
    const dir = await makeTmpDir();
    const streamContent = [
      '[2026-01-01T00:00:00Z] Session started (model: sonnet)',
      '[2026-01-01T00:00:01Z] Reading src/index.ts',
      '[2026-01-01T00:00:02Z] $ npm test',
    ].join('\n') + '\n';
    await setupSession(dir, 'legacy-1', { streamLog: streamContent });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('legacy');
    expect(result.activity).toBeDefined();
    expect(result.activity!.length).toBe(3);
    expect(result.activity![0]).toContain('Session started');
  });

  test('events.jsonl path derived from stream.log by replacing filename', () => {
    const logPath = '/repo/.forge/sessions/abc/stream.log';
    const eventsPath = logPath.replace(/stream\.log$/, 'events.jsonl');
    expect(eventsPath).toBe('/repo/.forge/sessions/abc/events.jsonl');
  });

  test('returns null session when no latest-session.json', async () => {
    const dir = await makeTmpDir();
    await fs.mkdir(path.join(dir, '.forge'), { recursive: true });
    // No latest-session.json written

    const result = await simulateWatchHandler(dir);
    expect(result.session).toBeNull();
  });
});

// ── Structured events parsing ────────────────────────────────

describe('structured events from events.jsonl', () => {
  test('includes thinking_delta events for agent reasoning visibility', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'think-1' }),
      { type: 'thinking_delta', timestamp: new Date().toISOString(), content: 'Analyzing codebase...' },
      { type: 'text_delta', timestamp: new Date().toISOString(), content: 'Found it.' },
      makeSessionEnd(),
    ];
    await setupSession(dir, 'think-1', { events });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('structured');
    const thinking = result.events!.find(e => e.type === 'thinking_delta');
    expect(thinking).toBeDefined();
    expect(thinking!.content).toBe('Analyzing codebase...');
  });

  test('includes tool_call_result events for tool output visibility', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'tool-1' }),
      { type: 'tool_call_start', timestamp: new Date().toISOString(), toolName: 'Read', input: { file_path: 'src/core.ts' } },
      { type: 'tool_call_result', timestamp: new Date().toISOString(), toolName: 'Read', output: 'file contents here...' },
      makeSessionEnd(),
    ];
    await setupSession(dir, 'tool-1', { events });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('structured');
    const toolResult = result.events!.find(e => e.type === 'tool_call_result');
    expect(toolResult).toBeDefined();
    expect(toolResult!.output).toBe('file contents here...');
  });

  test('returns typed event objects with type, timestamp, and type-specific fields', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'typed-1' }),
      { type: 'tool_call_start', timestamp: '2026-01-01T00:00:01Z', toolName: 'Bash', toolUseId: 'tu-1', input: { command: 'echo hi' } },
      makeSessionEnd({ numTurns: 5, costUsd: 0.50 }),
    ];
    await setupSession(dir, 'typed-1', { events });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('structured');

    for (const event of result.events!) {
      // Every event has type and timestamp
      expect(event.type).toBeTruthy();
      expect(event.timestamp).toBeTruthy();
    }

    // Check type-specific fields
    const toolEvent = result.events![1];
    expect(toolEvent.toolName).toBe('Bash');
    expect(toolEvent.toolUseId).toBe('tu-1');
    expect(toolEvent.input).toEqual({ command: 'echo hi' });
  });

  test('respects maxLines limit for events', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [makeSessionStart({ sessionId: 'limit-1' })];
    for (let i = 0; i < 100; i++) {
      events.push({ type: 'text_delta', timestamp: new Date().toISOString(), content: `msg-${i}` });
    }
    events.push(makeSessionEnd());
    await setupSession(dir, 'limit-1', { events });

    const result = await simulateWatchHandler(dir, 10);
    expect(result.format).toBe('structured');
    expect(result.events!.length).toBe(10);
    // Last event should be session_end (the actual last line)
    expect(result.events![result.events!.length - 1].type).toBe('session_end');
  });

  test('skips malformed JSON lines in events.jsonl', async () => {
    const dir = await makeTmpDir();
    const sessionDir = path.join(dir, '.forge', 'sessions', 'bad-json');
    await fs.mkdir(sessionDir, { recursive: true });

    const logPath = path.join(sessionDir, 'stream.log');
    const eventsPath = path.join(sessionDir, 'events.jsonl');
    await fs.writeFile(logPath, 'stream log\n');

    const lines = [
      JSON.stringify(makeSessionStart({ sessionId: 'bad-json' })),
      'this is not json <<<',
      JSON.stringify({ type: 'text_delta', timestamp: new Date().toISOString(), content: 'ok' }),
    ];
    await fs.writeFile(eventsPath, lines.join('\n'));
    await fs.writeFile(
      path.join(dir, '.forge', 'latest-session.json'),
      JSON.stringify({ sessionId: 'bad-json', logPath }),
    );

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('structured');
    expect(result.events!.length).toBe(2); // malformed line skipped
  });

  test('detects session completion from session_end event', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [
      makeSessionStart({ sessionId: 'done-1' }),
      makeSessionEnd({ status: 'success' }),
    ];
    await setupSession(dir, 'done-1', { events });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('structured');
    const lastEvent = result.events![result.events!.length - 1];
    expect(lastEvent.type).toBe('session_end');
  });
});

// ── Legacy fallback ──────────────────────────────────────────

describe('legacy fallback when events.jsonl does not exist', () => {
  test('returns stream.log lines in activity array', async () => {
    const dir = await makeTmpDir();
    const stream = [
      '[2026-01-01T00:00:00Z] Session started',
      '[2026-01-01T00:00:01Z] $ npm install',
      '[2026-01-01T00:00:05Z] Writing src/auth.ts',
      '[2026-01-01T00:00:10Z] Result: success (5 turns)',
    ].join('\n') + '\n';

    await setupSession(dir, 'legacy-full', { streamLog: stream });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('legacy');
    expect(result.activity).toHaveLength(4);
    expect(result.activity![0]).toContain('Session started');
    expect(result.activity![3]).toContain('Result: success');
  });

  test('strips ANSI escape codes from stream.log lines', async () => {
    const dir = await makeTmpDir();
    const stream = '[2026-01-01T00:00:00Z] \x1b[36mHighlighted\x1b[0m text\n';
    await setupSession(dir, 'ansi-1', { streamLog: stream });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('legacy');
    expect(result.activity![0]).not.toContain('\x1b[');
    expect(result.activity![0]).toContain('Highlighted text');
  });

  test('respects maxLines limit for stream.log', async () => {
    const dir = await makeTmpDir();
    const lines: string[] = [];
    for (let i = 0; i < 100; i++) {
      lines.push(`[2026-01-01T00:00:00Z] Line ${i}`);
    }
    await setupSession(dir, 'limit-legacy', { streamLog: lines.join('\n') + '\n' });

    const result = await simulateWatchHandler(dir, 10);
    expect(result.format).toBe('legacy');
    expect(result.activity!.length).toBe(10);
    // Should be the last 10 lines
    expect(result.activity![result.activity!.length - 1]).toContain('Line 99');
  });

  test('existing callers that inspect activity/lines field still work', async () => {
    const dir = await makeTmpDir();
    await setupSession(dir, 'compat-1', { streamLog: '[ts] Line 1\n[ts] Line 2\n' });

    const result = await simulateWatchHandler(dir);
    expect(result.format).toBe('legacy');
    // The activity field (renamed from lines) is populated
    expect(Array.isArray(result.activity)).toBe(true);
    expect(result.activity!.length).toBeGreaterThan(0);
  });
});

