describe('session ID tracking', () => {
  test('session ID is read from latest-session.json', async () => {
    const dir = await makeTmpDir();
    const events: SessionEvent[] = [makeSessionStart({ sessionId: 'per-task-1' })];
    await setupSession(dir, 'per-task-1', { events });

    const result = await simulateWatchHandler(dir);
    expect(result.session).toBe('per-task-1');
  });

  test('construct logPath directly from sessionId when known', () => {
    const sessionId = 'abc123';
    const cwd = '/repo';
    const logPath = path.join(cwd, '.forge', 'sessions', sessionId, 'stream.log');
    expect(logPath).toBe('/repo/.forge/sessions/abc123/stream.log');
    const eventsPath = logPath.replace(/stream\.log$/, 'events.jsonl');
    expect(eventsPath).toBe('/repo/.forge/sessions/abc123/events.jsonl');
  });
});
